fn style_tag_to_prop(tag: StyleTag) -> Result<StyleProp, JsValue> {
    Ok(match tag {
        StyleTag::BackgroundColor { color_r, color_g, color_b, color_a } => StyleProp::BackgroundColor(codec_color(color_r, color_g, color_b, color_a)),
        StyleTag::Opacity { value } => StyleProp::Opacity(value),
        StyleTag::BorderRadius { value } => StyleProp::BorderRadius(value),
        StyleTag::BorderWidth { value } => StyleProp::BorderWidth(value),
        StyleTag::BorderColor { color_r, color_g, color_b, color_a } => StyleProp::BorderColor(codec_color(color_r, color_g, color_b, color_a)),
        StyleTag::Width { dim_value, dim_unit } => StyleProp::Width(codec_dim(dim_value, dim_unit)),
        StyleTag::Height { dim_value, dim_unit } => StyleProp::Height(codec_dim(dim_value, dim_unit)),
        StyleTag::MinWidth { dim_value, dim_unit } => StyleProp::MinWidth(codec_dim(dim_value, dim_unit)),
        StyleTag::MinHeight { dim_value, dim_unit } => StyleProp::MinHeight(codec_dim(dim_value, dim_unit)),
        StyleTag::MaxWidth { dim_value, dim_unit } => StyleProp::MaxWidth(codec_dim(dim_value, dim_unit)),
        StyleTag::MaxHeight { dim_value, dim_unit } => StyleProp::MaxHeight(codec_dim(dim_value, dim_unit)),
        StyleTag::Display { value } => StyleProp::Display(codec_display(value)),
        StyleTag::FlexDirection { value } => StyleProp::FlexDirection(codec_flex_direction(value)),
        StyleTag::AlignItems { value } => StyleProp::AlignItems(codec_align_items(value)),
        StyleTag::JustifyContent { value } => StyleProp::JustifyContent(codec_justify_content(value)),
        StyleTag::Gap { dim_value, dim_unit } => StyleProp::Gap(codec_dim(dim_value, dim_unit)),
        StyleTag::Padding { dim_value, dim_unit } => StyleProp::Padding(codec_dim(dim_value, dim_unit)),
        StyleTag::PaddingTop { dim_value, dim_unit } => StyleProp::PaddingTop(codec_dim(dim_value, dim_unit)),
        StyleTag::PaddingRight { dim_value, dim_unit } => StyleProp::PaddingRight(codec_dim(dim_value, dim_unit)),
        StyleTag::PaddingBottom { dim_value, dim_unit } => StyleProp::PaddingBottom(codec_dim(dim_value, dim_unit)),
        StyleTag::PaddingLeft { dim_value, dim_unit } => StyleProp::PaddingLeft(codec_dim(dim_value, dim_unit)),
        StyleTag::Margin { dim_value, dim_unit } => StyleProp::Margin(codec_dim(dim_value, dim_unit)),
        StyleTag::MarginTop { dim_value, dim_unit } => StyleProp::MarginTop(codec_dim(dim_value, dim_unit)),
        StyleTag::MarginRight { dim_value, dim_unit } => StyleProp::MarginRight(codec_dim(dim_value, dim_unit)),
        StyleTag::MarginBottom { dim_value, dim_unit } => StyleProp::MarginBottom(codec_dim(dim_value, dim_unit)),
        StyleTag::MarginLeft { dim_value, dim_unit } => StyleProp::MarginLeft(codec_dim(dim_value, dim_unit)),
        StyleTag::FontSize { value } => StyleProp::FontSize(value),
        StyleTag::Color { color_r, color_g, color_b, color_a } => StyleProp::Color(codec_color(color_r, color_g, color_b, color_a)),
        StyleTag::ZIndex { value } => StyleProp::ZIndex(value as i32),
        StyleTag::FontFamily { family } => StyleProp::FontFamily(family),
        StyleTag::FlexGrow { value } => StyleProp::FlexGrow(value),
        StyleTag::FontWeight { value } => StyleProp::FontWeight(value),
        StyleTag::FontStyle { value } => StyleProp::FontStyle(codec_font_style(value)),
        StyleTag::TextDecoration { value } => StyleProp::TextDecoration(codec_text_decoration(value)),
        StyleTag::DefaultColor { color_r, color_g, color_b, color_a } => StyleProp::DefaultColor(codec_color(color_r, color_g, color_b, color_a)),
        StyleTag::DefaultFontFamily { family } => StyleProp::DefaultFontFamily(family),
        StyleTag::DefaultFontSize { value } => StyleProp::DefaultFontSize(value),
        StyleTag::DefaultFontWeight { value } => StyleProp::DefaultFontWeight(value),
        StyleTag::GridTemplateColumns { tracks } => StyleProp::GridTemplateColumns(tracks.into_iter().map(|(value, unit)| codec_dim(value, unit)).collect()),
        StyleTag::GridTemplateRows { tracks } => StyleProp::GridTemplateRows(tracks.into_iter().map(|(value, unit)| codec_dim(value, unit)).collect()),
        StyleTag::FlexShrink { value } => StyleProp::FlexShrink(value),
        StyleTag::FlexBasis { dim_value, dim_unit } => StyleProp::FlexBasis(codec_dim(dim_value, dim_unit)),
        StyleTag::AlignSelf { value } => StyleProp::AlignSelf(codec_align_self(value)),
        StyleTag::AlignContent { value } => StyleProp::AlignContent(codec_align_content(value)),
        StyleTag::FlexWrap { value } => StyleProp::FlexWrap(codec_flex_wrap(value)),
        StyleTag::BorderStyle { value } => StyleProp::BorderStyle(codec_border_style(value)),
    })
}

pub fn decode_style_packet(packed: &[f32]) -> Result<Vec<StyleProp>, JsValue> {
    let mut out = Vec::new();
    let mut i = 0usize;
    while i < packed.len() {
        let (tag, next) = parse_next_style_tag(packed, i)
            .map_err(|e| JsValue::from_str(e))?;
        i = next;
        out.push(style_tag_to_prop(tag)?);
    }
    Ok(out)
}

#[derive(Debug, Clone, PartialEq)]
pub enum EventWireValue {
    Number(f64),
    Text(String),
}

pub fn encode_event_wire(ev: &hayate_core::Event) -> Vec<EventWireValue> {
    match ev {
        hayate_core::Event::Click { target_id, x, y } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(0.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Number(*x as f64));
            out.push(EventWireValue::Number(*y as f64));
            out
        }
        hayate_core::Event::Focus { target_id } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(1.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out
        }
        hayate_core::Event::Blur { target_id } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(2.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out
        }
        hayate_core::Event::TextInput { target_id, text } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(3.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Text(text.clone()));
            out
        }
        hayate_core::Event::CompositionStart { target_id, text } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(4.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Text(text.clone()));
            out
        }
        hayate_core::Event::CompositionUpdate { target_id, text } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(5.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Text(text.clone()));
            out
        }
        hayate_core::Event::CompositionEnd { target_id, text } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(6.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Text(text.clone()));
            out
        }
        hayate_core::Event::Scroll { target_id, delta_x, delta_y } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(7.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Number(*delta_x as f64));
            out.push(EventWireValue::Number(*delta_y as f64));
            out
        }
        hayate_core::Event::Resize { width, height } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(8.0));
            out.push(EventWireValue::Number(*width as f64));
            out.push(EventWireValue::Number(*height as f64));
            out
        }
        hayate_core::Event::ActiveEnd { target_id } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(9.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out
        }
        hayate_core::Event::HoverEnter { target_id } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(10.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out
        }
        hayate_core::Event::HoverLeave { target_id } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(11.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out
        }
        hayate_core::Event::KeyDown { target_id, key, modifiers } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(12.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out.push(EventWireValue::Text(key.clone()));
            out.push(EventWireValue::Number(*modifiers as f64));
            out
        }
        hayate_core::Event::ActiveStart { target_id } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(13.0));
            out.push(EventWireValue::Number(target_id.to_u64() as f64));
            out
        }
        hayate_core::Event::PointerMove { x, y } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(14.0));
            out.push(EventWireValue::Number(*x as f64));
            out.push(EventWireValue::Number(*y as f64));
            out
        }
        hayate_core::Event::FetchFont { family } => {
            let mut out = Vec::new();
            out.push(EventWireValue::Number(15.0));
            out.push(EventWireValue::Text(family.clone()));
            out
        }
    }
}

pub fn encode_event(ev: &hayate_core::Event) -> js_sys::Array {
    use wasm_bindgen::JsValue;
    let sub = js_sys::Array::new();
    for atom in encode_event_wire(ev) {
        match atom {
            EventWireValue::Number(n) => { sub.push(&JsValue::from_f64(n)); }
            EventWireValue::Text(s) => { sub.push(&JsValue::from_str(&s)); }
        }
    }
    sub
}

pub fn encode_events(events: &[hayate_core::Event]) -> js_sys::Array {
    let result = js_sys::Array::new();
    for ev in events {
        result.push(&encode_event(ev));
    }
    result
}

pub fn encode_deliveries(deliveries: &[hayate_core::EventDelivery]) -> js_sys::Array {
    let result = js_sys::Array::new();
    for delivery in deliveries {
        let sub = encode_event(&delivery.event);
        let row = js_sys::Array::new();
        row.push(&JsValue::from_f64(delivery.listener_id.to_u64() as f64));
        for i in 0..sub.length() {
            row.push(&sub.get(i));
        }
        result.push(&row);
    }
    result
}
